{"query":"
      query FetchEntries($search: String, $startDateRange: [QueryArgument], $limit: Int!, $offset: Int!, $siteLanguage: [String]) {
        allEntries: entries(
          search: $search
          section: ["exhibitions", "events", "media"]
          startDate: $startDateRange
          limit: $limit
          offset: $offset
          orderBy: "startDate DESC, id DESC"
          language: $siteLanguage
        ) {
          id
          title
          slug
          url
          ... on event_Entry {
            sectionHandle
            subtitleText
            image {
              id
              url @transform(handle: "image600x")
            }
            startDate
            endDate
          }
          ... on exhibition_Entry {
            sectionHandle
            subtitleText
            images(limit: 1) {
              id
              url @transform(handle: "image600x")
            }
            startDate
            endDate
          }
          ... on medium_Entry {
            sectionHandle
            subtitleText
            image {
              id
              url @transform(handle: "image600x")
            }
            startDate
            mediaType {
              id
              title
              slug
            } 
          }
        }
        allCount: entryCount(
          search: $search
          section: ["exhibitions", "events", "media"]
          startDate: $startDateRange
        )
      }
    ","variables":{"siteLanguage":"de-AT","search":null,"sections":null,"sectionMediaFilter":null,"mediaFilters":null,"startDateRange":null,"limit":15,"offset":$_2}}

