{"query":"
      query FetchDateEntries($eventType: [QueryArgument], $date: [QueryArgument], $limit: Int!, $offset: Int!) {
        dateEntries: entries(
          type: "date"
          date: $date
          eventType: $eventType
          limit: $limit
          offset: $offset
          orderBy: "date ASC, id DESC"
        ) {
          id
          ownerId
          ... on date_Entry {
            date
            startTime
            endTime
            detailsText
            bookingDisabled
            bookingType
            bookingLink {
              url
            }
            eventType {
              id
              title
            }
          }
        }
        dateCount: entryCount(
          type: "date"
          date: $date
          eventType: $eventType
        )
      }
    ","variables":{"siteLanguage":"de-AT","eventType":null,"rangeStart":[">=2021-01-01"],"rangeEnd":["<=2021-12-31"],"date":["AND",">= 2021-01-01","<= 2021-12-31"],"limit":20,"offset":$_5}}
